const req = $input.first().json;
return [{
  json: {
    client_id: req.body.client_id,
    timestamp: req.headers['x-caiac-timestamp'],
    signature: req.headers['x-caiac-signature'],
    token: req.body.token
  }
}];

const session = $input.first().json;
const body = $('Receive Chat Request').first().json.body;

return [{
  json: {
    user_id: session.user_id,
    role: session.role,
    client_id: session.client_id,
    slug: session.slug,
    name: session.name,
    email: session.email,
    message: body.message,
    session_id: body.session_id ?? 'no-session',
    quick_action_key: body.quick_action_key ?? null
  }
}];

const input = $input.first().json;

// Detect which trigger path ran.
// Webhook path: Get Role Permissions outputs { visible_roles: [...] }
// Sub-workflow path: caller provides the full context object directly.
if ('visible_roles' in input) {
  // Webhook path — assemble from auth chain nodes that already ran
  const token = $('Check Token Valid').first().json;
  const auth = $('Call Full Auth').first().json;
  return [{
    json: {
      slug: token.slug,
      message: token.message,
      session_id: token.session_id ?? 'no-session',
      user_id: token.user_id ?? null,
      role: token.role ?? 'user',
      features: auth.features ?? {},
      quick_action_key: token.quick_action_key ?? null,
      allowed_roles: Array.isArray(input.visible_roles) ? input.visible_roles : ['public'],
      source: 'webhook',
    }
  }];
} else {
  // Sub-workflow path — caller is responsible for auth; provides full context
  if (!input.slug) throw new Error('Sub-workflow input missing required field: slug');
  if (!input.message) throw new Error('Sub-workflow input missing required field: message');
  return [{
    json: {
      slug: input.slug,
      message: input.message,
      session_id: input.session_id ?? 'no-session',
      user_id: input.user_id ?? null,
      role: input.role ?? 'public',
      features: input.features ?? {},
      quick_action_key: input.quick_action_key ?? null,
      allowed_roles: Array.isArray(input.allowed_roles) ? input.allowed_roles : ['public'],
      source: 'sub-workflow',
    }
  }];
}

const client = $('Get Client Config').first().json;
const auth = $('Normalize Auth Context').first().json;

if (!client || !client.id) {
  throw new Error('Invalid client');
}

if (!client.active) {
  throw new Error('Client account is inactive');
}

if (!auth.message || !auth.message.trim()) {
  throw new Error('Message is required');
}

return [{
  json: {
    message: auth.message.trim(),
    role: auth.role,
    allowed_roles: auth.allowed_roles,
    user_id: auth.user_id ?? null,
    session_id: auth.session_id,
    client_id: client.id,
    slug: client.slug,
    config: client.config,
    ollama_url: client.config.ai.ollama_url,
    embed_model: client.config.ai.embed_model,
    chat_model: client.config.ai.model,
    qdrant_url: client.config.ai.qdrant_url,
    qdrant_collection: client.config.ai.qdrant_collection,
    search_limit: client.config.ai.search_limit,
    system_prompt: client.config.ai.system_prompt,
    fallback_message: client.config.ai.fallback_message ?? "I don't have information on that topic in the available documents.",
    message_index: Date.now(),
    quick_action_key: auth.quick_action_key ?? null,
    features: auth.features,
    source: auth.source,
  }
}];

const scrollResult = $input.first().json;
const validated = $('Validate Request').first().json;

const points = scrollResult.result?.points ?? [];
const sorted = points
  .filter(p => p.payload?.question && p.payload?.answer)
  .sort((a, b) => (a.payload.message_index ?? 0) - (b.payload.message_index ?? 0));

const history_turns = [];
for (const p of sorted) {
  history_turns.push({ role: 'user', content: p.payload.question });
  history_turns.push({ role: 'assistant', content: p.payload.answer });
}

return [{
  json: {
    ...validated,
    history_turns
  }
}];

const hits = $input.first().json.result;
const validated = $('Validate Request').first().json;

const docHits = hits.filter(h => !h.payload.type || h.payload.type === 'document');
const knowledgeHits = hits.filter(h => h.payload.type === 'knowledge');
const historyHits = hits.filter(h => h.payload.type === 'chat_history' && h.score >= 0.85);

const knowledgeQuestions = new Set(
  knowledgeHits.map(h => h.payload.question?.toLowerCase().trim()).filter(Boolean)
);

const seenQuestions = new Set();
const dedupedHistory = [];
for (const h of historyHits) {
  const q = h.payload.question?.toLowerCase().trim();
  if (q && !knowledgeQuestions.has(q) && !seenQuestions.has(q)) {
    seenQuestions.add(q);
    dedupedHistory.push(h);
  }
}

const merged = [...docHits, ...knowledgeHits, ...dedupedHistory.slice(0, 2)]
  .sort((a, b) => b.score - a.score)
  .slice(0, validated.search_limit);

return [{ json: { result: merged } }];

const reranked = $input.first().json.results;
const validated = $('Validate Request').first().json;
const history_turns = $('Build History Turns').first().json.history_turns ?? [];

const context = reranked.length > 0
  ? reranked.map((c, i) => `[${i+1}] (${c.source ?? 'Document'})\n${c.text}`).join('\n\n')
  : 'No relevant documents found.';

const sources = reranked.map(c => ({
  source: c.source ?? 'Document',
  role: c.role ?? 'public',
  score: c.rerank_score,
  type: c.type ?? 'document'
}));

const messages = [
  { role: 'system', content: validated.system_prompt + '\n\nContext:\n' + context.replace(/\n/g, ' ') },
  ...history_turns,
  { role: 'user', content: validated.message }
];

return [{
  json: {
    message: validated.message,
    context,
    sources,
    messages,
    system_prompt: validated.system_prompt,
    chat_model: validated.chat_model,
    ollama_url: validated.ollama_url,
    session_id: validated.session_id,
    user_id: validated.user_id,
    client_id: validated.client_id,
    quick_action_key: validated.quick_action_key,
    period: new Date().toISOString().slice(0, 7),
  }
}];

const v = $('Validate Request').first().json;
return [{
  json: {
    response: v.fallback_message,
    sources: [],
    session_id: v.session_id,
    message_index: 0,
  }
}];

const raw = $input.first().json;
const context = $('Build Context').first().json;

// Handle Ollama format ({ message: { content } }) and Claude format ({ content: [{ text }] })
const response = raw.message?.content ?? raw.content?.[0]?.text ?? '';

return [{
  json: {
    response,
    sources: context.sources,
    session_id: context.session_id,
    message_index: $('Validate Request').first().json.message_index,
    quick_action_key: context.quick_action_key,
  }
}];

try {
  const validated = $('Validate Request').first().json;
  const buildContext = $('Build Context').first().json;
  const formatResponse = $('Format Response').first().json;
  const embedding = $('Embed Query').first().json.embedding;

  if (!validated) throw new Error('validated is null');
  if (!buildContext) throw new Error('buildContext is null');
  if (!formatResponse) throw new Error('formatResponse is null');
  if (!embedding) throw new Error('embedding is null');

  const seed = validated.session_id + ':' + validated.message_index;
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    hash = ((hash << 5) - hash + seed.charCodeAt(i)) | 0;
  }
  const pointId = Math.abs(hash) % 2147483647 || 1;

  return [{
    json: {
      point: {
        id: pointId,
        vector: embedding,
        payload: {
          type: 'chat_history',
          client_id: buildContext.client_id,
          user_id: buildContext.user_id,
          session_id: buildContext.session_id,
          role: validated.role,
          question: buildContext.message,
          answer: formatResponse.response,
          sources: formatResponse.sources,
          timestamp: new Date().toISOString(),
          message_index: validated.message_index
        }
      },
      qdrant_url: validated.qdrant_url,
      qdrant_collection: validated.qdrant_collection,
      qdrant_upsert_url: validated.qdrant_url + '/collections/' + validated.qdrant_collection + '/points'
    }
  }];
} catch(e) {
  throw new Error('Prepare History Point failed: ' + e.message);
}

const f = $('Format Response').first().json;
return [{
  json: {
    response: f.response,
    sources: f.sources ?? [],
    session_id: f.session_id,
    message_index: f.message_index,
  }
}];
